// ETAPA 1 - Validacion de entrada IoT
const run_id = `RUN-IOT-${Date.now()}-${Math.random().toString(36).substr(2,6).toUpperCase()}`;
const start_ts = new Date().toISOString();
const body = $input.item.json.body || {};

const errores = [];

// Validacion de campos obligatorios
if (!body.sensor_id || typeof body.sensor_id !== 'string') errores.push('sensor_id requerido (string)');
if (body.temperature === undefined || body.temperature === null) errores.push('temperature requerido');
if (body.humidity === undefined || body.humidity === null) errores.push('humidity requerido');
if (body.co2 === undefined) errores.push('co2 requerido');

// Validacion de rangos fisicamente posibles
const temp = parseFloat(body.temperature);
const hum = parseFloat(body.humidity);
const co2 = parseFloat(body.co2);

if (!isNaN(temp) && (temp < -50 || temp > 100)) errores.push(`temperature fuera de rango fisico: ${temp}`);
if (!isNaN(hum) && (hum < 0 || hum > 100)) errores.push(`humidity fuera de rango fisico: ${hum}`);
if (!isNaN(co2) && (co2 < 0 || co2 > 5000)) errores.push(`co2 fuera de rango fisico: ${co2}`);

const valido = errores.length === 0;

const lectura = valido ? {
  sensor_id: body.sensor_id,
  temperature: Math.round(temp * 10) / 10,
  humidity: Math.round(hum * 10) / 10,
  co2: Math.round(co2),
  timestamp: body.timestamp || start_ts,
  location: body.location || null
} : null;

console.log(JSON.stringify({
  run_id, etapa: 'E1_validacion_iot',
  status: valido ? 'ok' : 'fail',
  errores, start_ts
}));

return [{ json: { run_id, start_ts, valido, errores, lectura } }];
